import{_ as o,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"79. Professional Development Leave","description":"","frontmatter":{"title":"79. Professional Development Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave"]},"headers":[],"relativePath":"ebas/allied-health/education-pd/79-professional-development-leave.md","filePath":"ebas/allied-health/education-pd/79-professional-development-leave.md"}'),r={name:"ebas/allied-health/education-pd/79-professional-development-leave.md"};function s(i,e,p,l,d,h){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_79-professional-development-leave" tabindex="-1">79. Professional Development Leave <a class="header-anchor" href="#_79-professional-development-leave" aria-label="Permalink to &quot;79. Professional Development Leave&quot;">​</a></h1><p><strong>79.1</strong> Professional Development is the means by which members of a profession maintain, improve and broaden their knowledge and expertise, and develop personal and professional qualities by:</p><p><strong>(a)</strong> reviewing practice;</p><p><strong>(b)</strong> identifying learning needs;</p><p><strong>(c)</strong> planning and participating in relevant learning activities; and</p><p><strong>(d)</strong> reflecting on the value of those activities. Professional development may be for the Employee’s current position or job, or another position or job that would be covered by this Agreement.</p><p><strong>79.2</strong> Professional Development Activities Professional development activities include, but are not limited to:</p><p><strong>(a)</strong> short courses;</p><p><strong>(b)</strong> further tertiary studies;</p><p><strong>(c)</strong> research;</p><p><strong>(d)</strong> study (including home study);</p><p><strong>(e)</strong> training;</p><p><strong>(f)</strong> attending a conference;</p><p><strong>(g)</strong> attending a seminar;</p><p><strong>(h)</strong> attending a webinar; and</p><p><strong>(i)</strong> attending a lecture.</p><p><strong>79.3</strong> Amount of Professional Development Leave</p><p><strong>(a)</strong> A full-time Employee is entitled to seven (7) days’ paid professional development leave per calendar year, in addition to other prescribed leave entitlements. Part- time Employees have a pro rata entitlement.</p><p><strong>(b)</strong> An Employee may utilise professional development leave for part of a single day.</p><p>Example: An Employee may use their professional development leave to attend 14 half- day professional development activities in a year of service provided that the total period will not exceed seven (7) days.</p><p><strong>79.4</strong> Payment</p><p><strong>(a)</strong> Day for the purposes of professional development leave is the Employee&#39;s usual shift length on the day the leave is taken. For example, a night shift worker who takes a day of professional development leave for a 10-hour night shift is entitled to 10 hours&#39; payment.</p><p><strong>(b)</strong> In circumstances where an Employee takes professional development leave on a day the Employee would not otherwise work, see subclause 79.8.</p><p><strong>79.5</strong> Accumulation of Professional Development Leave The leave is cumulative over two (2) calendar years.</p><p><strong>79.6</strong> Application Process</p><p><strong>(a)</strong> Professional Development Leave is available only on written application by the Employee. Where practicable, the application must be made at least six (6) weeks prior to the proposed professional development leave date(s).</p><p><strong>(b)</strong> The application must include:</p><p><strong>(i)</strong> the proposed date(s);</p><p><strong>(ii)</strong> a brief description of the nature of the professional development activity to be undertaken and its applicability to the Employee’s profession; and</p><p><strong>(iii)</strong> where the leave is taken to attend a conference or seminar, the name, venue and date/time.</p><p><strong>(c)</strong> For the avoidance of doubt, only professional development activities that an Employee makes an application for in accordance with this subclause 79.6 which are approved can be deducted from the Employee’s Professional Development Leave entitlement.</p><p><strong>79.7</strong> Response to Application</p><p><strong>(a)</strong> The application will be approved by the Employer unless there are exceptional circumstances that exist that justify non-approval, save that where an application for approval is made less than six (6) weeks prior to the proposed date approval will not be unreasonably withheld by the Employer.</p><p><strong>(b)</strong> The Employer must notify the Employee in writing if the leave is approved or not within seven (7) days of the request being made.</p><p><strong>(c)</strong> If leave is not approved the reasons will be included in the written notification to the Employee.</p><p><strong>(d)</strong> Once professional development leave has been granted by the Employer it will only be revoked by mutual agreement which may be at the request of the Employee, save that the Employer will not unreasonably refuse a request by an Employee to revoke the granting of leave.</p><p><strong>79.8</strong> Professional development activities occurring on a day the Employee would not otherwise work</p><p><strong>(a)</strong> Where a request for professional development leave which is approved by the Employer covers a period where the Employee is not rostered to work (e.g. on</p><p>weekends, ADOs or after hours) then the Employer will provide time off in lieu for the period of the course.</p><p><strong>(b)</strong> Time in lieu in this subclause 79.8 is on the basis of time for time at ordinary rates and does not include any benefit or payment for any overtime, penalties or allowances under this Agreement which would normally be paid for such periods of duty.</p><p><strong>(c)</strong> Instead of time in lieu in accordance with this subclause 79.8, the Employer and Employee may mutually agree to the Employee being paid for the period at the Employee’s ordinary time rate of pay.</p><p><strong>79.9</strong> Report Back An Employee may be required to report back on a seminar or conference, provided they are allocated sufficient time during their ordinary hours of work to prepare for and deliver this.</p><p><strong>79.10</strong> Mandatory Training</p><p><strong>(a)</strong> Any education or training (however titled):</p><p><strong>(i)</strong> the Employer requires an Employee to attend, such as fire, workplace bullying and equal opportunity training; and/or</p><p><strong>(ii)</strong> that is necessary for an Employee to perform their position/role, such as learning how to use a new piece of equipment or updates on policies / procedure; will occur within an Employee&#39;s paid time and no deduction will be made to an Employee&#39;s professional development leave entitlement for such education or training.</p><p><strong>(b)</strong> The Employer will indicate in writing (which may be in policy) to Employees if any education or training they are providing is education or training the Employee is required to attend.</p>',47)])])}const c=o(r,[["render",s]]);export{g as __pageData,c as default};
